import{_ as e,o as i,c as o,ac as t}from"./chunks/framework.DnBnwVZk.js";const g=JSON.parse('{"title":"SpringBoot源码-Fun Fact","description":"","frontmatter":{"date":"2020-04-24T12:09:02.000Z","categories":["Spring"],"tags":[null],"publish":true},"headers":[],"relativePath":"views/spring/2020/SpringBootCode.md","filePath":"views/spring/2020/SpringBootCode.md","lastUpdated":1775803235000}'),r={name:"views/spring/2020/SpringBootCode.md"};function n(l,a,s,p,c,d){return i(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1587730142000"},[...a[0]||(a[0]=[t('<h1 id="springboot源码-fun-fact" tabindex="-1">SpringBoot源码-Fun Fact <a class="header-anchor" href="#springboot源码-fun-fact" aria-label="Permalink to &quot;SpringBoot源码-Fun Fact&quot;">​</a></h1><h2 id="事件-event" tabindex="-1">事件-Event <a class="header-anchor" href="#事件-event" aria-label="Permalink to &quot;事件-Event&quot;">​</a></h2><ol><li>ApplicationStartingEvent：应用启动</li><li>ApplicationEnvironmentPreparedEvent：Environment初始化完成</li><li>contextPrepared：ApplicationContext实例创建并prepare完成</li><li>ApplicationPreparedEvent:读取并注册根Class的BeanDefinition完成</li><li>AutoConfigurationImportEvents</li><li>ContextRefreshedEvent:上下文refresh完成</li><li>ServletWebServerInitializedEvent：SerletWebServer初始化完成</li><li>ApplicationStartedEvent:整个应用启动完成</li></ol><h2 id="可用配置" tabindex="-1">可用配置 <a class="header-anchor" href="#可用配置" aria-label="Permalink to &quot;可用配置&quot;">​</a></h2><ul><li>context.initializer.classes：定义的类会在SpringApplication初始化完成ApplicationContext后，prepare过程中被调用initialize方法</li></ul><h2 id="aware" tabindex="-1">Aware <a class="header-anchor" href="#aware" aria-label="Permalink to &quot;Aware&quot;">​</a></h2><ul><li>BeanClassLoaderAware</li><li>BeanFactoryAware</li><li>EnvironmentAware</li><li>ResourceLoaderAware</li><li>LoadTimeWeaverAware</li></ul><h2 id="配置文件处理" tabindex="-1">配置文件处理 <a class="header-anchor" href="#配置文件处理" aria-label="Permalink to &quot;配置文件处理&quot;">​</a></h2><h3 id="_1-影响spring对配置文件加载的配置" tabindex="-1">1. 影响Spring对配置文件加载的配置 <a class="header-anchor" href="#_1-影响spring对配置文件加载的配置" aria-label="Permalink to &quot;1. 影响Spring对配置文件加载的配置&quot;">​</a></h3><ol><li>spring.profiles.active和spring.profiles.include:影响可以被加载的profile,间接影响文件名后缀部分</li><li>spring.config.location和spring.config.additional-location，影响查找配置文件的路径</li><li>默认的配置文件加载路径，<strong>注意，顺序是相反的</strong>：classpath:/,classpath:/config/,file:./,file:./config/</li><li>PropertySourceLoader类，影响加载配置文件的后缀，默认提供两个实现，分别是: <ul><li>org.springframework.boot.env.PropertiesPropertySourceLoader:加载.xml和.properties</li><li>org.springframework.boot.env.YamlPropertySourceLoader:加载yaml</li></ul></li></ol><h3 id="_2-读取配置文件的时机" tabindex="-1">2. 读取配置文件的时机 <a class="header-anchor" href="#_2-读取配置文件的时机" aria-label="Permalink to &quot;2. 读取配置文件的时机&quot;">​</a></h3><ol><li>org.springframework.boot.context.config.ConfigFileApplicationListener类，在EnvironmentPrepared事件广播后</li></ol><h2 id="auto-config原理" tabindex="-1">Auto Config原理 <a class="header-anchor" href="#auto-config原理" aria-label="Permalink to &quot;Auto Config原理&quot;">​</a></h2><h3 id="spring-boot-autoconfiguration包" tabindex="-1">spring-boot-autoconfiguration包 <a class="header-anchor" href="#spring-boot-autoconfiguration包" aria-label="Permalink to &quot;spring-boot-autoconfiguration包&quot;">​</a></h3><p>此包定义了很多默认的Bean，涵盖了数据库，消息队列，云环境，各种插件等，随便扫一眼可以看到jdbc,amqp,kafka,es,neo4j等，包罗万象，这些Bean和配置通过@Conditional和@ConditionalOnMissingBean等来进行动态加载，尤其是@Conditional(XXXX.class)，在Spring加载配置阶段，通过在classpath上筛选依赖的Class是否存在，可以快速加载默认Bean，也可以剔除依赖不满足的Bean</p><h3 id="autoconfigurationimportselector" tabindex="-1">AutoConfigurationImportSelector <a class="header-anchor" href="#autoconfigurationimportselector" aria-label="Permalink to &quot;AutoConfigurationImportSelector&quot;">​</a></h3><p>此类负责加载所有的@EnableAutoConfiguration注解的类，并根据各个类的@Conditional配置来进行筛选</p>',17)])])}const h=e(r,[["render",n]]);export{g as __pageData,h as default};
